/**
 * pisot-stabilized-intelligence.ts — TypeScript mirror of PisotStabilizedIntelligence.lean.
 *
 * Mirrors:
 *   - isTopologicallyTight (Pisot drift = 0)
 *   - intelligenceMetric (teleportation density)
 *   - isLuminary (Luminary dimension predicate)
 *   - aeon_is_luminary (dim 8 proof)
 *   - luminary_symmetry_2_8 (dims 2 and 8 share Pell +4)
 *   - luminary_generation_2_to_4, luminary_generation_4_to_8 (Binary Mitosis path)
 *
 * The Lean proofs verify these identities via native_decide;
 * this module is the runtime that the Betti compiler calls into.
 */

import { fib, lucas, pellDiscriminant } from './boundary-topology';
import type { VectorState } from './topological-memoization';

// ============================================================================
// Topological Tightness (Θ)
// ============================================================================

/**
 * Compute the Pisot drift for a dimension n.
 *
 * A system is 'Tight' if it sits on the Pisot manifold (drift = 0).
 * Drift is defined as L_n² - 5·F_n² - 4·(-1)^n, which is the residual
 * after the expected Pell discriminant ±4 is accounted for.
 *
 * Mirrors PisotStabilizedIntelligence.computeDrift → 0 for tight dimensions.
 */
export function computePisotDrift(n: number): number {
  const l = lucas(n);
  const f = fib(n);
  const pell = l * l - 5 * f * f;
  // Expected Pell residual: +4 for even n, -4 for odd n
  const expected = n % 2 === 0 ? 4 : -4;
  return Math.abs(pell - expected);
}

/**
 * Topological Tightness predicate.
 * A system at dimension n is 'Topologically Tight' if it sits on the Pisot
 * manifold (drift = 0), meaning L_n² - 5·F_n² = ±4 exactly.
 *
 * Mirrors PisotStabilizedIntelligence.isTopologicallyTight.
 */
export function isTopologicallyTight(n: number): boolean {
  return computePisotDrift(n) === 0;
}

// ============================================================================
// Intelligence Metric (η)
// ============================================================================

/**
 * Intelligence metric: the percentage of operations resolved through
 * zero-latency teleportation.
 *
 * Mirrors PisotStabilizedIntelligence.intelligenceMetric.
 */
export function intelligenceMetric(
  teleportHits: number,
  totalOps: number
): number {
  if (totalOps === 0) return 0;
  return Math.floor((teleportHits * 100) / totalOps);
}

// ============================================================================
// Luminary Predicate
// ============================================================================

/**
 * A 'Luminary' state is one that is Topologically Tight (perfectly aligned
 * with the Pisot manifold). The Swarm must prioritize these states in the
 * memoization cache to prevent 'Bule Deficits' (information loss due to
 * non-ergodic drift).
 *
 * Mirrors PisotStabilizedIntelligence.isLuminary.
 */
export function isLuminary(v: VectorState): boolean {
  return isTopologicallyTight(v.n);
}

// ============================================================================
// Verification — runtime checks against Lean proofs
// ============================================================================

/**
 * Result of the Aeon Luminary verification.
 */
export interface AeonLuminaryVerification {
  readonly dimension: number;
  readonly lucasValue: number;
  readonly fibValue: number;
  readonly pellResidual: number;
  readonly drift: number;
  readonly isLuminary: boolean;
  /** Proved in Lean: aeon_is_luminary. */
  readonly verified: boolean;
}

/**
 * Verify that dimension 8 (The Aeon) is a Luminary.
 *
 * lucas 8 = 47, fib 8 = 21.
 * 47² - 5 × 21² = 2209 - 2205 = 4. Drift = 0.
 *
 * Proved in Lean: aeon_is_luminary.
 */
export function verifyAeonIsLuminary(): AeonLuminaryVerification {
  const n = 8;
  const l = lucas(n);
  const f = fib(n);
  const pell = pellDiscriminant(n);
  const drift = computePisotDrift(n);
  return {
    dimension: n,
    lucasValue: l,
    fibValue: f,
    pellResidual: pell,
    drift,
    isLuminary: drift === 0,
    verified: drift === 0,
  };
}

/**
 * Result of the Luminary Symmetry verification.
 */
export interface LuminarySymmetryVerification {
  /** Dimension 2: L₂² - 5·F₂² should equal 4. */
  readonly dim2PellResidual: number;
  /** Dimension 8: L₈² - 5·F₈² should equal 4. */
  readonly dim8PellResidual: number;
  /** Both should be exactly +4 (positive Luminary constant). */
  readonly bothPositive4: boolean;
  /** Proved in Lean: luminary_symmetry_2_8. */
  readonly verified: boolean;
}

/**
 * Verify the symmetry between dimensions 2 and 8.
 * Both exhibit the Positive Luminary constant (4).
 *
 * Proved in Lean: luminary_symmetry_2_8.
 */
export function verifyLuminarySymmetry(): LuminarySymmetryVerification {
  const pell2 = pellDiscriminant(2);
  const pell8 = pellDiscriminant(8);
  return {
    dim2PellResidual: pell2,
    dim8PellResidual: pell8,
    bothPositive4: pell2 === 4 && pell8 === 4,
    verified: pell2 === 4 && pell8 === 4,
  };
}

/**
 * Result of the Binary Mitosis verification.
 */
export interface BinaryMitosisVerification {
  /** L₄ should equal L₂² - 2 = 3² - 2 = 7. */
  readonly generation2to4: {
    readonly lucasSource: number;
    readonly lucasSourceSquaredMinus2: number;
    readonly lucasTarget: number;
    readonly holds: boolean;
  };
  /** L₈ should equal L₄² - 2 = 7² - 2 = 47. */
  readonly generation4to8: {
    readonly lucasSource: number;
    readonly lucasSourceSquaredMinus2: number;
    readonly lucasTarget: number;
    readonly holds: boolean;
  };
  /** Proved in Lean: luminary_generation_2_to_4, luminary_generation_4_to_8. */
  readonly verified: boolean;
}

/**
 * Verify Binary Mitosis: the Lucas-Lehmer squaring path.
 *
 * L₂ = 3, L₄ = 3² - 2 = 7, L₈ = 7² - 2 = 47.
 *
 * This recursive squaring creates the 'Fractal Tightness' where each
 * generation of the Swarm is a perfect square of the previous's manifold trace.
 *
 * Proved in Lean: luminary_generation_2_to_4, luminary_generation_4_to_8.
 */
export function verifyBinaryMitosis(): BinaryMitosisVerification {
  const l2 = lucas(2);
  const l4 = lucas(4);
  const l8 = lucas(8);

  const gen2to4 = {
    lucasSource: l2,
    lucasSourceSquaredMinus2: l2 * l2 - 2,
    lucasTarget: l4,
    holds: l4 === l2 * l2 - 2,
  };

  const gen4to8 = {
    lucasSource: l4,
    lucasSourceSquaredMinus2: l4 * l4 - 2,
    lucasTarget: l8,
    holds: l8 === l4 * l4 - 2,
  };

  return {
    generation2to4: gen2to4,
    generation4to8: gen4to8,
    verified: gen2to4.holds && gen4to8.holds,
  };
}

/**
 * Full Pisot-Stabilized Intelligence verification suite.
 */
export function verifyPisotStabilizedIntelligence(): {
  readonly aeonLuminary: AeonLuminaryVerification;
  readonly luminarySymmetry: LuminarySymmetryVerification;
  readonly binaryMitosis: BinaryMitosisVerification;
  readonly allHold: boolean;
} {
  const aeonLuminary = verifyAeonIsLuminary();
  const luminarySymmetry = verifyLuminarySymmetry();
  const binaryMitosis = verifyBinaryMitosis();
  return {
    aeonLuminary,
    luminarySymmetry,
    binaryMitosis,
    allHold:
      aeonLuminary.verified &&
      luminarySymmetry.verified &&
      binaryMitosis.verified,
  };
}
